{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/EmptyEnumTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.ruleset.standard.rules.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

/**
 * Test for empty enum classes - regression test for issue where empty enum causes NoSuchElementException
 */
class EmptyEnumTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnCallSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule, so that the formattedCode in the unit test looks
                // correct.
                RuleProvider { IndentationRule() },
            ),
        )

    @Test
    fun `Given that an enum class is empty, then no error should be raised`() {
        val code =
            """
            enum class TestView {
            }
            """.trimIndent()

        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given that an enum class is empty and terminated with semicolon, then no error should be raised`() {
        val code =
            """
            enum class TestView {
                ;
            }
            """.trimIndent()

        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given that an enum class is empty and has properties, then no error should be raised`() {
        val code =
            """
            enum class TestView(val id: Int) {
                ;

                companion object {
                    const val EMPTY = 0
                }
            }
            """.trimIndent()

        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }
}"}

